INSERT INTO `v1_d203170e00282985860cf58f263cbc36a3f3fafe8f5fca442446b10e5e76d2d1` VALUES (11, 0, 10, 945, 1, 110411, 19450021, 0, 1, 0, "どうしたんだ、ユイ？\nあいつのために\nわざわざ弁当作ってきたんだろ？\nとっとと誘えばいいじゃないか。");
INSERT INTO `v1_d203170e00282985860cf58f263cbc36a3f3fafe8f5fca442446b10e5e76d2d1` VALUES (91, "", "", 945, "", 0, 19450022, "", "", "", "");
